import sys

def max_subarray_sum(arr):
    max_sum = float('-inf')
    current_sum = 0
    for num in arr:
        current_sum = max(num, current_sum + num)
        max_sum = max(max_sum, current_sum)
    return max_sum

def max_circular_subarray_sum(arr):
    max_wrap_sum = 0
    total_sum = 0
    min_sum = float('inf')
    current_min_sum = 0
    for num in arr:
        total_sum += num
        current_min_sum = min(num, current_min_sum + num)
        min_sum = min(min_sum, current_min_sum)
        max_wrap_sum = max(max_wrap_sum, total_sum - min_sum)
    if max_wrap_sum == 0:
        return max_subarray_sum(arr)
    else:
        return max(max_subarray_sum(arr), max_wrap_sum)

def main():
    n = int(input())
    arr = list(map(int, input().split()))
    result = max_circular_subarray_sum(arr)
    print(result)

if __name__ == "__main__":
    main()
